/* global Office, Excel */

Office.onReady(() => {
  document.getElementById("runBtn").onclick = runWebenoidAI;
  setupMenu();
});

/* ===============================
   CHAT UI HELPERS
================================ */

function addMessage(text, type = "ai") {
  const outputBox = document.getElementById("resultBox");
  const div = document.createElement("div");
  div.className = `message ${type}`;
  div.innerText = text;
  outputBox.appendChild(div);
  outputBox.scrollTop = outputBox.scrollHeight;
  return div;
}

/* ===============================
   MAIN ACTION (AI CONNECTED)
================================ */

async function runWebenoidAI() {
  const input = document.getElementById("prompt");
  const prompt = input.value.trim();
  if (!prompt) return;

  addMessage(prompt, "user");
  input.value = "";

  const loading = addMessage("Webenoid AI is analyzing data…", "loading");

  try {
    // 1️⃣ Read selected Excel range
    const range = await getSelectedRange();

    // 2️⃣ Call AI backend
    const aiResult = await callAI(prompt, range);

    if (!aiResult || !aiResult.operation) {
      loading.innerText = "❌ AI could not understand. Try again.";
      loading.classList.remove("loading");
      return;
    }

    // 3️⃣ Convert AI decision → Excel formula
    const formula = buildFormulaFromAI(aiResult.operation, range);

    // 4️⃣ Write formula to Excel
    const total = await writeFormulaBelow(range, formula);
    loading.remove();

    // 5️⃣ Show result
    const result = document.createElement("div");
    result.className = "message ai";
    result.innerHTML = `
      ✅ Done
      <div class="result-card">
        <b>AI Decision:</b> ${aiResult.reason}<br/><br/>
        <b>Result:</b> ${total}<br/>
        <b>Formula:</b> ${formula}
      </div>
    `;
    document.getElementById("resultBox").appendChild(result);

  } catch (e) {
  if (e.message === "NO_NUMERIC_DATA") {
    loading.innerText = "❌ No numeric data found";
  } else {
    loading.innerText = "❌ Select a column with numbers";
  }
  loading.classList.remove("loading");
}

}

/* ===============================
   EXCEL HELPERS
================================ */

async function getSelectedRange() {
  return Excel.run(async (context) => {
    const range = context.workbook.getSelectedRange();
    range.load(["rowIndex", "columnIndex", "rowCount", "values"]);
    await context.sync();

    const values = range.values;

    // Extract only numeric rows
    const numericRowIndexes = [];

    values.forEach((row, i) => {
      if (typeof row[0] === "number") {
        numericRowIndexes.push(i);
      }
    });

    if (numericRowIndexes.length === 0) {
      throw new Error("NO_NUMERIC_DATA");
    }

    const first = numericRowIndexes[0];
    const last = numericRowIndexes[numericRowIndexes.length - 1];

    return {
      rowIndex: range.rowIndex + first,
      columnIndex: range.columnIndex,
      rowCount: last - first + 1
    };
  });
}

function buildFormulaFromAI(operation, range) {
  const col = columnNumberToName(range.columnIndex + 1);
  const start = range.rowIndex + 1;
  const end = range.rowIndex + range.rowCount;
  const target = `${col}${start}:${col}${end}`;

  switch (operation) {
    case "sum":
      return `=SUM(${target})`;
    case "avg":
      return `=AVERAGE(${target})`;
    case "max":
      return `=MAX(${target})`;
    case "min":
      return `=MIN(${target})`;
    default:
      return null;
  }
}

async function writeFormulaBelow(range, formula) {
  return Excel.run(async (context) => {
    const sheet = context.workbook.worksheets.getActiveWorksheet();

    const labelRow = range.rowIndex + range.rowCount;
    const valueRow = labelRow + 1;
    const col = range.columnIndex;

    sheet.getCell(labelRow, col).values = [["Total"]];
    sheet.getCell(labelRow, col).format.font.bold = true;

    const valueCell = sheet.getCell(valueRow, col);
    valueCell.formulas = [[formula]];
    valueCell.format.font.bold = true;

    await context.sync();

    valueCell.load("values");
    await context.sync();

    return valueCell.values[0][0];
  });
}

/* ===============================
   AI BACKEND CALL
================================ */

async function callAI(prompt, range) {
  const colLetter = columnNumberToName(range.columnIndex + 1);

  const response = await fetch("http://localhost:8000/analyze", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      prompt: prompt,
      column: colLetter,
      startRow: range.rowIndex + 1,
      endRow: range.rowIndex + range.rowCount
    })
  });

  return await response.json();
}

/* ===============================
   UTIL
================================ */

function columnNumberToName(num) {
  let name = "";
  while (num > 0) {
    const rem = (num - 1) % 26;
    name = String.fromCharCode(65 + rem) + name;
    num = Math.floor((num - 1) / 26);
  }
  return name;
}

/* ===============================
   3-DOTS MENU
================================ */

function setupMenu() {
  const menuBtn = document.getElementById("menuBtn");
  const menu = document.getElementById("menuDropdown");

  if (!menuBtn || !menu) return;

  menuBtn.addEventListener("click", (e) => {
    e.stopPropagation();
    menu.classList.toggle("hidden");
  });

  document.addEventListener("click", () => {
    menu.classList.add("hidden");
  });

  menu.querySelectorAll(".menu-item").forEach(item => {
    item.onclick = () => {
      menu.classList.add("hidden");
      handleMenuAction(item.dataset.action);
    };
  });
}

function handleMenuAction(action) {
  const output = document.getElementById("resultBox");
  const input = document.getElementById("prompt");

  switch (action) {
    case "clear":
      output.innerHTML = "";
      break;

    case "reset":
      input.value = "";
      input.focus();
      break;

    case "help":
      addMessage(
        "Try typing:\n• add values\n• calculate total\n• highest salary\n• average pay\n\nSelect a column first.",
        "ai"
      );
      break;

    case "about":
      addMessage(
        "Webenoid AI\nVersion 1.0\nAI-powered Excel Copilot",
        "ai"
      );
      break;
  }
}
